mapper.sql:
where d.repository_scope = #{repositoryScope}

    and exists (
        select 1
        from source_product_warehouse_detail wd
        where wd.source_dimension_group_key = d.source_dimension_group_key
          and wd.connection_code = #{connectionCode}
    )


    and d.source_sku_group_key = #{sourceSkuGroupKey}


    and d.system_kind = #{systemKind}


    and exists (
        select 1
        from source_product_warehouse_detail wd
        where wd.source_dimension_group_key = d.source_dimension_group_key
          and wd.master_warehouse_name like concat('%', #{masterWarehouseName}, '%')
    )


    and d.master_sku like concat('%', #{masterSku}, '%')


    and (
        d.master_product_name like concat('%', #{productName}, '%')
        or d.product_alias_name like concat('%', #{productName}, '%')
        or d.product_description like concat('%', #{productName}, '%')
    )


    and (
        d.main_code like concat('%', #{identifyCodeKeyword}, '%')
        or d.other_code like concat('%', #{identifyCodeKeyword}, '%')
        or d.fnsku like concat('%', #{identifyCodeKeyword}, '%')
    )


    and (
        d.cat1_name like concat('%', #{categoryKeyword}, '%')
        or d.cat2_name like concat('%', #{categoryKeyword}, '%')
        or d.cat3_name like concat('%', #{categoryKeyword}, '%')
    )


    and d.approve_status = #{approveStatus}


    and d.dangerous_cargo = #{dangerousCargo}


    and d.status = #{status}


    and d.pairing_status = #{pairingStatus}


    and (
        d.search_text like concat('%', #{keyword}, '%')
        or d.source_connection_codes like concat('%', #{keyword}, '%')
        or d.source_warehouse_names like concat('%', #{keyword}, '%')
        or d.system_sku like concat('%', #{keyword}, '%')
        or d.system_sku_name like concat('%', #{keyword}, '%')
        or d.customer_name like concat('%', #{keyword}, '%')
    )

select affected.source_sku_group_key
from (
    select distinct  as source_sku_group_key
    from upstream_system_sku_candidate c
    where c.connection_code = #{connectionCode}
) affected

select affected.source_stock_group_key
from (
    select distinct  as source_stock_group_key
    from upstream_system_sku_inventory_snapshot s
    where s.connection_code = #{connectionCode}
    union
    select distinct d.source_stock_group_key
    from source_warehouse_stock_detail d
    where d.connection_code = #{connectionCode}
) affected

where g.repository_scope = #{repositoryScope}

    and g.source_stock_group_key = #{sourceStockGroupKey}


    and g.source_stock_group_key in (

    )


    and g.inventory_scope = #{inventoryScope}


    and g.status = #{status}


    and g.warehouse_pairing_status = #{warehousePairingStatus}


    and g.sku_pairing_status = #{skuPairingStatus}


    and exists (
        select 1
        from source_warehouse_stock_filter_metric fm
        where fm.source_stock_group_key = g.source_stock_group_key
          and fm.filter_type = 'INVENTORY_ATTRIBUTE'
          and fm.filter_value = #{inventoryAttribute}
    )


    and exists (
        select 1
        from source_warehouse_stock_filter_metric fm
        where fm.source_stock_group_key = g.source_stock_group_key
          and fm.filter_type = 'MASTER_WAREHOUSE'
          and fm.filter_value = #{masterWarehouseName}
    )


    and exists (
        select 1
        from source_warehouse_stock_filter_metric fm
        where fm.source_stock_group_key = g.source_stock_group_key
          and fm.filter_type = 'UPSTREAM_WAREHOUSE'
          and fm.filter_value = #{upstreamWarehouseCode}
    )


    and (
        g.master_warehouse_names like concat('%', #{masterWarehouseKeyword}, '%')
        or exists (
            select 1
            from source_warehouse_stock_filter_metric fm
            where fm.source_stock_group_key = g.source_stock_group_key
              and fm.filter_type = 'MASTER_WAREHOUSE'
              and fm.filter_label like concat('%', #{masterWarehouseKeyword}, '%')
        )
    )


    and (
        g.upstream_warehouse_codes like concat('%', #{warehouseKeyword}, '%')
        or g.upstream_warehouse_names like concat('%', #{warehouseKeyword}, '%')
        or g.system_warehouse_codes like concat('%', #{warehouseKeyword}, '%')
        or g.system_warehouse_names like concat('%', #{warehouseKeyword}, '%')
    )


    and (
        g.search_text like concat('%', #{keyword}, '%')
        or g.master_sku like concat('%', #{keyword}, '%')
        or g.master_product_name like concat('%', #{keyword}, '%')
    )


    and g.total_quantity >= #{totalQuantityMin}


    and g.total_quantity <= #{totalQuantityMax}


    and g.available_quantity >= #{availableQuantityMin}


    and g.available_quantity <= #{availableQuantityMax}


    and g.locked_quantity >= #{lockedQuantityMin}


    and g.locked_quantity <= #{lockedQuantityMax}


    and g.in_transit_quantity >= #{inTransitQuantityMin}


    and g.in_transit_quantity <= #{inTransitQuantityMax}

mapper.select:
select d.inventory_snapshot_id, d.connection_code, d.system_kind, d.master_warehouse_name, d.upstream_warehouse_code, d.upstream_warehouse_name, d.master_sku, d.master_product_name, d.inventory_scope, d.inventory_attribute, d.batch_no, d.location_code, d.total_quantity, d.available_quantity, d.locked_quantity, d.in_transit_quantity, d.boxed_quantity, d.unboxed_quantity, d.system_warehouse_code, d.system_warehouse_name, d.system_sku, d.system_sku_name, d.customer_name, d.warehouse_pairing_status, d.sku_pairing_status, d.status, d.sync_batch_id, null as source_payload_json, d.source_payload_hash, d.first_seen_time, d.last_seen_time, d.update_time from source_warehouse_stock_detail d where d.repository_scope = #{repositoryScope}
and d.source_stock_group_key = #{sourceStockGroupKey}
and d.connection_code = #{connectionCode}
and d.inventory_scope = #{inventoryScope}
and d.inventory_attribute = #{inventoryAttribute}
and d.master_warehouse_name = #{masterWarehouseName}
and d.upstream_warehouse_code = #{upstreamWarehouseCode}
and d.master_warehouse_name like concat('%', #{masterWarehouseKeyword}, '%')
and ( d.upstream_warehouse_code like concat('%', #{warehouseKeyword}, '%') or d.upstream_warehouse_name like concat('%', #{warehouseKeyword}, '%') or d.system_warehouse_code like concat('%', #{warehouseKeyword}, '%') or d.system_warehouse_name like concat('%', #{warehouseKeyword}, '%') )
and d.status = #{status}
and d.warehouse_pairing_status = #{warehousePairingStatus}
and d.sku_pairing_status = #{skuPairingStatus}
and ( d.master_sku like concat('%', #{keyword}, '%') or d.master_product_name like concat('%', #{keyword}, '%') or d.system_sku like concat('%', #{keyword}, '%') or d.system_sku_name like concat('%', #{keyword}, '%') or d.customer_name like concat('%', #{keyword}, '%') )
order by d.master_warehouse_name asc, d.upstream_warehouse_code asc, d.inventory_attribute asc, d.batch_no asc, d.location_code asc, d.inventory_snapshot_id asc

select fm.filter_value as label, fm.filter_value as value, fm.filter_value as code, fm.filter_value as name, fm.filter_value as searchText from source_warehouse_stock_filter_metric fm where fm.repository_scope = #{repositoryScope} and fm.filter_type = 'MASTER_WAREHOUSE' and nullif(fm.filter_value, '') is not null
and fm.inventory_scope = #{inventoryScope}
group by fm.filter_value order by fm.filter_value asc

select case when nullif(max(fm.filter_label), '') is null or max(fm.filter_label) = fm.filter_value then fm.filter_value else concat(fm.filter_value, ' / ', max(fm.filter_label)) end as label, fm.filter_value as value, fm.filter_value as code, max(fm.filter_label) as name, concat(fm.filter_value, ' ', coalesce(max(fm.filter_label), '')) as searchText from source_warehouse_stock_filter_metric fm where fm.repository_scope = #{repositoryScope} and fm.filter_type = 'UPSTREAM_WAREHOUSE' and nullif(fm.filter_value, '') is not null
and fm.inventory_scope = #{inventoryScope}
group by fm.filter_value order by label asc

select distinct wd.source_dimension_group_key, w.warehouse_id, w.warehouse_code, w.warehouse_name, w.warehouse_kind, w.settlement_currency from source_product_warehouse_detail wd inner join upstream_system_connection c on c.connection_code = wd.connection_code inner join upstream_system_warehouse_pairing p on p.connection_code = wd.connection_code and p.pairing_role = case when c.settlement_type = 'self-operated-receivable' then 'QUOTE' else 'FULFILLMENT' end and p.status = 'ACTIVE' inner join warehouse w on w.warehouse_code = p.system_warehouse_code and w.warehouse_kind = 'official' and w.status = '0' where wd.repository_scope = 'OFFICIAL_MASTER' and wd.status = 'ACTIVE' and wd.source_dimension_group_key in
#{sourceDimensionGroupKey}
order by wd.source_dimension_group_key asc, w.warehouse_id asc

select d.repository_scope as source_scope, d.source_sku_group_key, d.source_dimension_group_key, d.master_sku, d.master_product_name as master_product_name_snapshot, d.source_payload_hash, coalesce(wd.wms_payload_hash, '') as wms_payload_hash, case when d.wms_length is not null and d.wms_width is not null and d.wms_height is not null and d.wms_weight is not null then d.wms_length else d.product_length end as measure_length_cm, case when d.wms_length is not null and d.wms_width is not null and d.wms_height is not null and d.wms_weight is not null then d.wms_width else d.product_width end as measure_width_cm, case when d.wms_length is not null and d.wms_width is not null and d.wms_height is not null and d.wms_weight is not null then d.wms_height else d.product_height end as measure_height_cm, case when d.wms_length is not null and d.wms_width is not null and d.wms_height is not null and d.wms_weight is not null then d.wms_weight else d.product_weight end as measure_weight_kg, case when d.wms_length is not null and d.wms_width is not null and d.wms_height is not null and d.wms_weight is not null then 'WMS' else 'PRODUCT' end as measure_source, d.currency_code, d.source_warehouse_names, d.warehouse_count as source_warehouse_count from source_product_dimension_group d left join ( select source_dimension_group_key, max(coalesce(wms_payload_hash, '')) as wms_payload_hash from source_product_warehouse_detail where repository_scope = 'OFFICIAL_MASTER' group by source_dimension_group_key ) wd on wd.source_dimension_group_key = d.source_dimension_group_key where d.repository_scope = 'OFFICIAL_MASTER' and d.status = 'ACTIVE' and d.source_dimension_group_key in
#{sourceDimensionGroupKey}
order by d.source_dimension_group_key asc

select distinct connection_code
from upstream_system_sku_pairing
where system_sku = #{systemSku}
  and master_sku = #{masterSku}
order by connection_code asc

mapper.delete:
delete from upstream_system_sku_pairing
where system_sku = #{systemSku}
  and connection_code in

      #{connectionCode}

delete from source_warehouse_stock_detail
where repository_scope = 'OFFICIAL_MASTER'
  and connection_code = #{connectionCode}

mapper.select:
select d.repository_scope as sourceScope, d.master_sku as masterSku, d.master_product_name as masterProductName, d.master_warehouse_name as masterWarehouseName, sum(coalesce(d.total_quantity, 0)) as sourceTotalQty, sum(coalesce(d.available_quantity, 0)) as sourceAvailableQty, sum(coalesce(d.in_transit_quantity, 0)) as sourceInTransitQty, max(d.update_time) as sourceSnapshotTime from source_warehouse_stock_detail d where d.repository_scope = 'OFFICIAL_MASTER' and d.inventory_scope = 'COMPREHENSIVE' and d.inventory_attribute = '0' and nullif(d.master_warehouse_name, '') is not null and (
(d.repository_scope = #{sourceKey.sourceScope} and d.master_sku = #{sourceKey.masterSku} and coalesce(d.master_product_name, '') = coalesce(#{sourceKey.masterProductName}, ''))
) group by d.repository_scope, d.master_sku, d.master_product_name, d.master_warehouse_name order by d.repository_scope asc, d.master_sku asc, d.master_product_name asc, d.master_warehouse_name asc

mapper.update:
update upstream_system_sku_inventory_snapshot
set status = 'MISSING',
    update_time = sysdate()
where connection_code = #{connectionCode}
  and sync_batch_id <> #{syncBatchId}

mapper.select:
select s.*,
       c.system_kind,
       c.master_warehouse_name,
       case when nullif(s.system_warehouse_code, '') is null then 'UNASSIGNED' else 'PAIRED' end as warehouse_pairing_status,
       case when nullif(s.system_sku, '') is null then 'UNASSIGNED' else 'PAIRED' end as sku_pairing_status
from upstream_system_sku_inventory_snapshot s
left join upstream_system_connection c on c.connection_code = s.connection_code
where 1 = 1

    and s.connection_code = #{connectionCode}


    and s.status = #{status}


    and s.inventory_scope = #{inventoryScope}


    and s.inventory_attribute = #{inventoryAttribute}


    and c.master_warehouse_name = #{masterWarehouseName}


    and s.upstream_warehouse_code = #{upstreamWarehouseCode}


    and c.master_warehouse_name like concat('%', #{masterWarehouseKeyword}, '%')


    and (
        s.upstream_warehouse_code like concat('%', #{warehouseKeyword}, '%')
        or s.upstream_warehouse_name like concat('%', #{warehouseKeyword}, '%')
        or s.system_warehouse_code like concat('%', #{warehouseKeyword}, '%')
        or s.system_warehouse_name like concat('%', #{warehouseKeyword}, '%')
    )




            and nullif(s.system_warehouse_code, '') is not null


            and nullif(s.system_warehouse_code, '') is null






            and nullif(s.system_sku, '') is not null


            and nullif(s.system_sku, '') is null




    and (
        s.master_sku like concat('%', #{keyword}, '%')
        or s.master_product_name like concat('%', #{keyword}, '%')
        or s.system_sku like concat('%', #{keyword}, '%')
        or s.system_sku_name like concat('%', #{keyword}, '%')
        or s.customer_name like concat('%', #{keyword}, '%')
    )


    and s.total_quantity >= #{totalQuantityMin}


    and s.total_quantity <= #{totalQuantityMax}


    and s.available_quantity >= #{availableQuantityMin}


    and s.available_quantity <= #{availableQuantityMax}


    and s.locked_quantity >= #{lockedQuantityMin}


    and s.locked_quantity <= #{lockedQuantityMax}


    and s.in_transit_quantity >= #{inTransitQuantityMin}


    and s.in_transit_quantity <= #{inTransitQuantityMax}

order by s.update_time desc, s.upstream_warehouse_code asc, s.master_sku asc

select *
from upstream_system_sku_candidate
where connection_code = #{connectionCode}
  and master_sku = #{masterSku}
limit 1

select *
from upstream_system_sku_pairing
where connection_code = #{connectionCode}
  and sku_pairing_id = #{skuPairingId}
limit 1

